using UnityEngine;

public class PlayerData
{
    // PUBLIC — accessible from anywhere
    public string name;
    public int level;

    // PRIVATE — only accessible inside this class
    private int health;
    private int maxHealth;
    private string secretCode;

    // PROTECTED — accessible in this class and derived classes
    protected int experience;
    protected int attackPower;

    // INTERNAL — accessible anywhere in the same assembly (project)
    internal int id;

    // Constructor
    public PlayerData(string playerName, int startingHealth)
    {
        name = playerName;
        health = startingHealth;
        maxHealth = startingHealth;
        level = 1;
        experience = 0;
        attackPower = 10;
        secretCode = "ABC123";
        id = Random.Range(1, 1000);
        Debug.Log("Player " + name + " created!");
    }

    // Public method to access private data safely
    public int GetHealth()
    {
        return health;
    }

    public void TakeDamage(int damage)
    {
        health -= damage;
        if (health < 0) health = 0;
        Debug.Log(name + " took " + damage + " damage! Health: " + health);
    }

    public void Heal(int amount)
    {
        health += amount;
        if (health > maxHealth) health = maxHealth;
        Debug.Log(name + " healed! Health: " + health);
    }

    // Protected method — can be used by derived classes
    protected void GainExperience(int amount)
    {
        experience += amount;
        Debug.Log(name + " gained " + amount + " XP!");
        if (experience >= level * 100)
        {
            LevelUp();
        }
    }

    private void LevelUp()
    {
        level++;
        maxHealth += 20;
        health = maxHealth;
        attackPower += 5;
        experience = 0;
        Debug.Log("*** " + name + " reached level " + level + "! ***");
    }

    public void DisplayStats()
    {
        Debug.Log("=== " + name + " ===");
        Debug.Log("Level: " + level);
        Debug.Log("Health: " + health + "/" + maxHealth);
        Debug.Log("Attack: " + attackPower);
        Debug.Log("XP: " + experience + "/" + (level * 100));
        Debug.Log("ID: " + id);
        // secretCode is private — not displayed
    }
}

public class Warrior : PlayerData
{
    public Warrior(string name) : base(name, 120)
    {
        attackPower = 15;  // Can access protected field
    }

    public void KillEnemy()
    {
        // Can access protected method from base class
        GainExperience(50);
        Debug.Log("Enemy defeated!");
    }
}

public class AccessModifiers : MonoBehaviour
{
    void Start()
    {
        PlayerData hero = new PlayerData("Hero", 100);

        // Public members are accessible
        Debug.Log("Name: " + hero.name);
        Debug.Log("Level: " + hero.level);

        // Private members are NOT accessible
        // hero.health = 50;  // ERROR!
        // Debug.Log(hero.secretCode);  // ERROR!

        // Protected members are NOT accessible outside the class
        // hero.experience = 100;  // ERROR!

        // Internal members are accessible (in the same assembly)
        Debug.Log("ID: " + hero.id);

        // Use public methods to interact with private data
        hero.TakeDamage(30);
        hero.Heal(20);
        hero.DisplayStats();

        // Warrior can access protected members
        Warrior warrior = new Warrior("Aragorn");
        warrior.KillEnemy();
        warrior.DisplayStats();
    }
}

phase2.brokenCode:
using UnityEngine;

public class Player
{
    private int health;

    // Forgot to make it public, so nothing can access it
    void SetHealth(int value)
    {
        health = value;
    }
}

public class AccessError : MonoBehaviour
{
    void Start()
    {
        Player p = new Player();
        // ERROR: SetHealth is private
        p.SetHealth(100);
    }
}

phase2.explanation:
`SetHealth` is `private` by default (since no access modifier was specified), so you can't call it from `AccessError`.

**The fix:**
```csharp
public void SetHealth(int value)  // ← Add public!
{
    health = value;
}
```

**Sharp-chan says:**
"If you want something to be accessible from outside, make it `public`. Otherwise, it stays `private` — and inaccessible."
